import React from 'react'
import {useState} from 'react'
import {useEffect} from 'react'


function UserDropdown() {
  let [users, setUsers] = useState([]);
  let [select, setSelect] = useState("");
  

  useEffect(()=>
  {
     fetch("https://jsonplaceholder.typicode.com/users")
     .then(res=>res.json())
     .then(data=>setUsers(data))
     .catch(err=>console.log(err));
  },[]);
  console.log(users);
  

  let handleChange = (e)=>
  {
      setSelect(e.target.value);
  }
 
  //selected user ka data search krne ke liye
  let userData = users.find((user) => user.name === select);

  return (
    <>
    <h3>Select any user for its description!!</h3>
    <select onChange={(e)=>handleChange(e)}>
      <option value="">Select any user..</option>
      {users.map((user)=>
      {
        
        return(
          
        <option value={user.name} key={user.id}>{user.name}</option>
      )
      })}
      
    </select>
    
    
    {
    userData && (
      <>
      <p>Name: {userData.name}</p>
      <p>Email: {userData.email}</p>
      <p>City: {userData.address.city}</p>
      <p>Company: {userData.company.name}</p>

      </>

    )
  }
   
    </>

  )
}



function App() {
  return (
    <UserDropdown />
  )
}

export default App

